const LOTUS_SCALLOP =
  "M110 20 C 104 18, 100 13, 103 9 C 105 6.2, 107.5 6, 110 6 C 112.5 6, 115 6.2, 117 9 C 120 13, 116 18, 110 20 Z";

const LOTUS_SEEDS = Array.from({ length: 6 }, (_, i) => ({
  x: rx(110, 8, i * 60 - 90),
  y: ry(110, 8, i * 60 - 90),
