"use client";

import { useEffect, useRef } from "react";

/**
 * Capped, lerped pointer parallax for the hanji layers.
 *
 * Writes two unitless custom properties (--giwa-px / --giwa-py, each in
 * [-1, 1]) onto the attached element; styles.css multiplies them into small
 * translate3d offsets (≤ 8px), so the cap lives in CSS next to the layers.
 *
 * Self-disabling: does nothing under reduced motion, on coarse pointers
 * (touch gets the calm, unmoving paper), or while `disabled` is true.
 * The rAF loop only runs while the pointer is actually settling — it parks
 * itself once the lerp converges and the pointer has left.
 */
export function usePointerParallax<T extends HTMLElement>(disabled: boolean) {
  const ref = useRef<T | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el || disabled) return;
    if (!window.matchMedia("(pointer: fine)").matches) return;

    let raf = 0;
    let running = false;
    let inside = false;
    let targetX = 0;
    let targetY = 0;
    let curX = 0;
    let curY = 0;
    let last = 0;

    const apply = () => {
      el.style.setProperty("--giwa-px", curX.toFixed(4));
      el.style.setProperty("--giwa-py", curY.toFixed(4));
    };

    const loop = (now: number) => {
      const dt = Math.min(now - last, 48) / 16.7; // 60fps-normalized, clamped
      last = now;
      const k = 1 - Math.pow(1 - 0.09, dt); // lerp 0.09/frame at 60fps
      curX += (targetX - curX) * k;
      curY += (targetY - curY) * k;
      apply();
      const settled =
        Math.abs(targetX - curX) < 0.002 && Math.abs(targetY - curY) < 0.002;
      if (settled && !inside) {
        curX = targetX;
        curY = targetY;
        apply();
        running = false;
        return;
      }
      raf = window.requestAnimationFrame(loop);
    };

    const wake = () => {
      if (running) return;
      running = true;
      last = performance.now();
      raf = window.requestAnimationFrame(loop);
    };

    const onMove = (e: PointerEvent) => {
      const rect = el.getBoundingClientRect();
      if (rect.width === 0 || rect.height === 0) return;
      inside = true;
      targetX = Math.min(1, Math.max(-1, ((e.clientX - rect.left) / rect.width) * 2 - 1));
      targetY = Math.min(1, Math.max(-1, ((e.clientY - rect.top) / rect.height) * 2 - 1));
      wake();
    };

    const onLeave = () => {
      inside = false;
      targetX = 0;
      targetY = 0;
      wake();
    };

    el.addEventListener("pointermove", onMove);
    el.addEventListener("pointerleave", onLeave);
    return () => {
      el.removeEventListener("pointermove", onMove);
      el.removeEventListener("pointerleave", onLeave);
      window.cancelAnimationFrame(raf);
      el.style.removeProperty("--giwa-px");
      el.style.removeProperty("--giwa-py");
    };
  }, [disabled]);

  return ref;
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. The pre-reveal state (opacity/translate,
 * and each motif's undrawn ink + unflooded paint) lives in styles.css and is
 * gated behind the `.giwa-js` root class, so every pattern and paragraph is
 * fully visible when JavaScript never runs.
 *
 * Elements that intersect in the same observer batch are staggered 90ms
 * apart via transition-delay, so a screenful never fades as one slab.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          el.style.transitionDelay = `${batch * 90}ms`;
          el.classList.add("is-visible");
          io.unobserve(el);
          batch += 1;
        }
      },
      { threshold: 0.18, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { fraunces, gowunBatang, songMyung } from "./fonts";
import Hero from "./components/Hero";
import Obangsaek from "./components/Obangsaek";
import PatternGallery from "./components/PatternGallery";
import HanjiMethod from "./components/HanjiMethod";
import GuildFooter from "./components/Footer";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";

/**
 * GIWA — 처마 아래 단청 / Under Painted Eaves.
 * A palace-eave restoration guild documenting dancheong — the five-color
 * painting under Korean roof eaves — and the obangsaek color system it is
 * built from. Hanji-light, Korean-led, every pattern drawn as SVG.
 *
 * `.giwa-js` is added on mount so every animated pre-state (undrawn ink,
 * unflooded paint, hidden reveals) is JS-gated — with JavaScript disabled
 * the page is simply the finished document: painted, legible, still.
 */
export default function GiwaPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLDivElement>(reduced);

  useEffect(() => {
    // Imperative on purpose: the class is a signal to CSS that JS is alive,
    // not React state — and it never changes once set.
    rootRef.current?.classList.add("giwa-js");
    window.parent?.postMessage({ type: "oneshot:ready", slug: "giwa" }, "*");
  }, []);

  return (
    <div
      ref={rootRef}
      lang="ko"
      className={`${songMyung.variable} ${gowunBatang.variable} ${fraunces.variable} giwa-root`}
    >
      <div className="giwa-page" ref={revealRef}>
        <Hero />
        <main>
          <Obangsaek />
          <PatternGallery />
          <HanjiMethod />
        </main>
        <GuildFooter />
      </div>

      {/* Hanji fiber: one static feTurbulence sheet multiplied over the
          whole page. Purely decorative, pointer-transparent. */}
      <div className="giwa-grain" aria-hidden="true">
        <svg width="100%" height="100%" preserveAspectRatio="none">
          <filter id="giwa-grain-f" x="0" y="0" width="100%" height="100%">
            <feTurbulence
              type="fractalNoise"
              baseFrequency="0.75"
              numOctaves="2"
              seed="3"
              stitchTiles="stitch"
            />
            <feColorMatrix
              type="matrix"
              values="0 0 0 0 0.28  0 0 0 0 0.23  0 0 0 0 0.16  0 0 0 0.07 0"
            />
          </filter>
          <rect width="100%" height="100%" filter="url(#giwa-grain-f)" />
        </svg>
      </div>
    </div>
  );
}

/* ==========================================================================
   GIWA — 처마 아래 단청 / Under Painted Eaves
   korean-traditional · hanji light · obangsaek pigments · every color a token
   Scoped by convention to .giwa-root; classes prefixed giwa-.
   ========================================================================== */

.giwa-root {
  /* -- palette: obangsaek + dancheong working pigments -------------------- */
  --giwa-hanji: #f4eee1;          /* 한지 — the paper everything sits on */
  --giwa-hanji-deep: #ece4d0;     /* pressed hanji — stage + card grounds */
  --giwa-heuk: #1f1c19;           /* 흑 먹 — body text, ink lines (14.7:1) */
  --giwa-seok: #8a3b2a;           /* 적 석간주 — accent, focus, ::selection (6.6:1) */
  --giwa-sam: #2f5d9e;            /* 청 삼청 — functional text allowed (5.7:1) */
  --giwa-noe: #58796f;            /* 뇌록 — decorative / large only (4.2:1) */
  --giwa-noe-deep: #3e5850;       /* derived: secondary text (6.7:1) */
  --giwa-hwang: #d9a441;          /* 황 석황 — decorative ONLY on hanji (2.0:1) */
  --giwa-baek: #f7f3e8;           /* 백 호분 — breath lines, card grounds */
  --giwa-tile: #3f3a34;           /* derived from 먹: fired-clay roof plane */
  --giwa-clay: #4b453e;           /* derived: tile-end discs */
  --giwa-line: rgba(31, 28, 25, 0.26); /* hairline rules */
  --giwa-accent: var(--giwa-seok);
  /* the living accent — obangsaek panels retint this; colors snap, never ease */
  --giwa-accent-live: var(--giwa-seok);

  /* -- type ---------------------------------------------------------------- */
  --giwa-font-display: var(--font-song-myung), "Song Myung", serif;
  --giwa-font-body: var(--font-gowun), "Gowun Batang", serif;
  --giwa-font-latin: var(--font-fraunces), "Fraunces", Georgia, serif;

  /* -- motion --------------------------------------------------------------- */
  --giwa-ease-out: cubic-bezier(0.16, 1, 0.3, 1);    /* reveals: fast in, long tail */
  --giwa-ease-brush: cubic-bezier(0.45, 0.05, 0.35, 1); /* ink draw: loaded brush */
  --giwa-ease-flood: cubic-bezier(0.6, 0, 0.18, 1);  /* color flood: commits, then rests */

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--giwa-hanji);
  color: var(--giwa-heuk);
  font-family: var(--giwa-font-body);
  font-size: clamp(16px, 0.5vw + 14px, 19px);
  line-height: 1.78;
  overflow-x: hidden;
  overflow-x: clip;
}

/* Latin is the guest voice: Fraunces, slightly quieter than the Korean */
.giwa-root [lang="en"] {
  font-family: var(--giwa-font-latin);
  letter-spacing: 0.005em;
}

/* Seokganju selection on hanji, scoped to the entry root */
.giwa-root ::selection {
  background: var(--giwa-seok);
  color: var(--giwa-hanji);
  text-shadow: none;
}

/* Keyboard focus: a seokganju ring with a faint pigment halo */
.giwa-root :focus-visible {
  outline: 2px solid var(--giwa-seok);
  outline-offset: 3px;
  border-radius: 2px;
  box-shadow: 0 0 0 6px rgba(138, 59, 42, 0.16);
}

.giwa-link {
  color: var(--giwa-seok);
  text-decoration: underline;
  text-decoration-color: rgba(138, 59, 42, 0.4);
  text-underline-offset: 3px;
}

.giwa-link:hover {
  text-decoration-color: var(--giwa-seok);
}

/* The content layer; the hanji grain sits above it, pointer-events: none */
.giwa-page {
  position: relative;
  z-index: 1;
}

/* Full-page hanji fiber — static, multiplied, decorative */
.giwa-grain {
  position: fixed;
  inset: 0;
  z-index: 40;
  pointer-events: none;
  mix-blend-mode: multiply;
